function login(e) {
	if (e == undefined) {
		return;
	}
	java.longToast(e);
}

function url() {
	login("启动")
	const baseUrl = java.connect(Get('rel')).url();
	$$$.rel = baseUrl;
	login('开始获取链接');
	const html = java.ajax(baseUrl);
	let allUrls = [];
	['china', 'first_line', 'second_line'].forEach(key => {
		const reg = new RegExp(`${key}\"><span>(.*?)<\\/span`);
		const match = html.match(reg);
		if (match && match[1]) {
			allUrls.push(match[1].replace(/\s+/g, ""));
		}
	});
	const uniqueUrls = [];
	allUrls.forEach(url => !uniqueUrls.includes(url) && url && uniqueUrls.push(url));
	$$$.urls = uniqueUrls
	java.log(JSON.stringify($$$.urls));
	login('获取成功' + n(2) + '到日志查看链接');
	return put($$$);
}

function n(e) {
	n = '\n';
	for (m = 1; m < e; m++) {
		n = n + '\n';
	}
	return n;
}

function typeSH(e) {
	if (e == undefined) {
		e = 0;
	}
	return SH[e];
