function Login() {
	const result = JSON.parse(source.getLoginInfo());
	var username = result['账号'];
	var password = result['密码'];
	var options = {
		body: `username=${username}&password=${password}&submit_login=1`,
		method: 'POST'
	};
	if (Get('urls')[0] == 1) {
		login('请先获取URL');
	} else if (Get('urls')[Get('ci')]) {
		login("\n⏳正在登录中，请等一会，很快就好...");
		var request = JSON.parse(java.log(java.ajax(Get('urls')[Get('ci')] + `/login,${JSON.stringify(options)}`)))
		if (request.status == '1') {
			login('✅ 登录成功')
		} else {
			login('❎ 登录失败')
		}
	} else {
		login('❌ 未获取到有效URL，请切换url');
	}
}

