ruleBookInfo.bookInfoInit:
(function(){
    var doc = org.jsoup.Jsoup.parse(result, baseUrl);

    function trim(s){ return s ? String(s).replace(/^\s+|\s+$/g, "") : ""; }
    function norm(s){ return trim(String(s || "").replace(/\u00A0/g, " ").replace(/[ \t\r\f\v]+/g, " ")); }
    function text(el){ return el ? trim(el.text()) : ""; }
    function own(el){ return el ? trim(el.ownText()) : ""; }
    function abs(el, attr){ return el ? trim(el.attr("abs:" + attr)) : ""; }
    function forumName(){
        var h = text(doc.select('.header h2 a').first());
        return h ? h.replace(/文學區/g, '文学区') : '';
    }
    function cleanTitle(t){
        t = trim(t || '');
        t = t.replace(/^\s*(?:[\[【][^\]】]{1,24}[\]】]\s*)+/g, '');
        t = t.replace(/\s*[\[【](?:更新|更至|更新至|更新到|完结|完結|番外.*?完).*?[\]】]\s*$/g, '');
        t = t.replace(/\s+\d+\s*\/\s*\d+\s*(?:\(\d+\s*\/\s*\d+\))?\s*$/g, '');
        return trim(t);
    }
    function decodeTextLines(s){
        s = String(s || '').replace(/\r/g, '');
        var arr = s.split('\n');
        for (var i = 0; i < arr.length; i++) arr[i] = org.jsoup.Jsoup.parse(arr[i]).text();
        return arr.join('\n');
    }
    function messageToText(msgEl){
        if (!msgEl) return '';
        var c = msgEl.clone();
        c.select('i.pstatus, script, style, rt, .quote, .pstatus, .aimg_tip, .jammer').remove();
        var rubies = c.select('ruby');
        for (var i = rubies.size() - 1; i >= 0; i--) rubies.get(i).unwrap();
        var as = c.select('a');
        for (var j = as.size() - 1; j >= 0; j--) as.get(j).unwrap();
        var h = String(c.html() || '');
        h = h.replace(/<br[^>]*>/ig, '\n');
        h = h.replace(/<hr[^>]*>/ig, '\n\n');
        h = h.replace(/<li[^>]*>/ig, '\n');
        h = h.replace(/<\/(?:li|div|p|section|blockquote|article|header|footer|aside|tr|td|th|ul|ol|table|tbody|thead|tfoot)>/ig, '\n');
        h = h.replace(/<h[1-6][^>]*>/ig, '\n\n');
        h = h.replace(/<\/h[1-6]>/ig, '\n\n');
        h = h.replace(/<[^>]+>/g, '');
        h = decodeTextLines(h);
        h = h.replace(/\u00A0/g, ' ');
        h = h.replace(/[ \t\f\v]+/g, ' ');
        h = h.replace(/ *\n */g, '\n');
        h = h.replace(/\n{3,}/g, '\n\n');
        return trim(h);
    }
    function linesFromMessage(msgEl){
        var txt = messageToText(msgEl);
        var raw = txt.split(/\n+/);
        var arr = [];
        for (var i = 0; i < raw.length; i++) {
            var line = norm(raw[i]);
            if (!line) continue;
            if (/^(本帖最后由|評分|评分|點評|点评|參與人數|参与人数|積分|积分|理由|查看全部评分)/.test(line)) continue;
            arr.push(line);
        }
        return arr;
    }
    var firstPost = doc.select('.plc.cl').first();
    var firstMsg = firstPost ? firstPost.select('.message').first() : null;
    var poster = firstPost ? text(firstPost.select('.authi .z a').first()) : '';
    var postTime = firstPost ? own(firstPost.select('.authi .mtime').first()) : '';
    var rawTitle = text(doc.select('.view_tit').first());

    var lines = linesFromMessage(firstMsg);
    var labelReg = /^(作品名稱|作品名称|作品名|書名|书名|標題|标题|題名|题名|原名|作者|原作|原著|作者名|翻譯|翻译|譯者|译者|校對|校对|圖源|图源|嵌字|漢化|汉化|簡介|简介|內容簡介|内容简介|原文简介|介紹|介绍|文案|作品連結|作品链接|連結|链接|原地址|生肉|作品標籤|作品标签|主题|主題)\s*[:：]?\s*$/;
    function isLabelLine(line){ return labelReg.test(trim(line || '')); }
    function cleanValue(v){ return trim(v || '').replace(/^[\[\【\(\（「『]+|[\]\】\)\）」』]+$/g, ''); }
    function extractSingle(keys, maxLen){
        var keyReg = '(?:' + keys.join('|') + ')';
        for (var i = 0; i < lines.length; i++) {
            var line = trim(lines[i]);
            var m = line.match(new RegExp('^' + keyReg + '\\s*[:：]\\s*(.+)$', 'i'));
            if (m) return cleanValue(m[1]).substring(0, maxLen || 120);
            if (line.match(new RegExp('^' + keyReg + '\\s*[:：]?\\s*$', 'i'))) {
                for (var j = i + 1; j < lines.length && j <= i + 3; j++) {
                    var n = trim(lines[j]);
                    if (!n) continue;
                    if (isLabelLine(n)) break;
                    return cleanValue(n).substring(0, maxLen || 120);
                }
            }
        }
        return '';
    }
    function extractIntro(){
        var keys = ['簡介','简介','內容簡介','内容简介','原文简介','介紹','介绍','文案'];
        var keyReg = '(?:' + keys.join('|') + ')';
        var start = -1, first = '';
        for (var i = 0; i < lines.length; i++) {
            var line = trim(lines[i]);
            var m = line.match(new RegExp('^' + keyReg + '\\s*[:：]\\s*(.*)$', 'i'));
            if (m) { start = i + 1; first = trim(m[1]); break; }
            if (line.match(new RegExp('^' + keyReg + '\\s*[:：]?\\s*$', 'i'))) { start = i + 1; break; }
        }
        if (start < 0) return '';
        var arr = [];
        if (first) arr.push(first);
        for (var j = start; j < lines.length; j++) {
            var x = trim(lines[j]);
            if (!x) continue;
            if (isLabelLine(x)) break;
            if (/^(目錄|目录|索引|主題|主题|作品標籤|作品标签|邊看邊翻|边看边翻|嚴禁劇透|严禁剧透|轉載請註明|转载请注明|生肉推薦串|生肉推荐串)/.test(x) && arr.length > 0) break;
            arr.push(x);
            if (arr.join('\n').length >= 260 && arr.length >= 2) break;
        }
        return trim(arr.join('\n')).substring(0, 320);
    }
    function normalizeTocUrl(u){
        u = String(u || '').replace(/([?&])__pid=\d+/g, '$1').replace(/&&+/g, '&').replace(/#pid\d+$/g, '');
        if (!u || u.indexOf('mod=viewthread') < 0) {
            var tm = String(baseUrl || '').match(/tid=(\d+)/);
            if (tm) u = 'https://bbs.yamibo.com/forum.php?mod=viewthread&tid=' + tm[1] + '&mobile=2';
        }
        if (u.indexOf('mobile=2') < 0) u += (u.indexOf('?') >= 0 ? '&' : '?') + 'mobile=2';
        return u.replace(/\?&/, '?');
    }

    var name = extractSingle(['作品名稱','作品名称','作品名','書名','书名','標題','标题','題名','题名','原名'], 180);
    if (!name) name = cleanTitle(rawTitle);

    var author = extractSingle(['作者','原作','原著','作者名'], 120);
    if (!author) author = trim(poster);

    var intro = extractIntro();
    if (!intro) {
        var metaDesc = trim(doc.select('meta[name=description]').attr('content'));
        if (metaDesc) intro = metaDesc.replace(/\s*,\s*百合会\s*$/i, '').substring(0, 260);
    }

    var forum = forumName();
    var kind = '百合会' + (forum ? ',' + forum : '');
    var onlyAuthor = doc.select('#nav-more-menu a[href*=authorid], a[rel=nofollow][href*=authorid]').first();
    var toc = normalizeTocUrl(abs(onlyAuthor, 'href') || String(baseUrl || ''));

    return {
        name: name,
        author: author,
        kind: kind,
        word: '',
        last: postTime,
        intro: intro,
        cover: '',
        toc: toc
    };
})()

