function updateConfig(key, value, message, gender) {
    if (key == "source" && hasValidCustomSource()) {
        showCustomSourceAlert();
        return;
    }

    try {
        var config = JSON.parse(source.getVariable());
        if (!config || !Array.isArray(config) || config.length === 0) {
            config = [{}];
        }
        config[0][key] = value;
        if (gender !== undefined) {
            config[0]["gender"] = gender;
        }
        source.setVariable(JSON.stringify(config));
        java.toast(message || "设置已更新");
    } catch(e) {
        var newConfig = {[key]: value};
        if (gender !== undefined) {
            newConfig["gender"] = gender;
        }
        source.setVariable(JSON.stringify([newConfig]));
        java.toast(message || "初始化设置");
    }
}

function get_user() {
    try {
        var encodedKey = getSecretKey();
        if (!encodedKey) {
            java.toast("❌ 未获取到密钥，请先登录");
            return;
        }

        var timestamp = Math.floor(Date.now() / 1000);
        var apiUrl = getServerHost() + '/query_key.php?key=' + encodedKey + '&t=' + timestamp;

        var response = java.ajax(apiUrl + "," + JSON.stringify({
            method: "GET",
            timeout: 10000
        }));

        var data = JSON.parse(response);

        if (data.data) {
            var userInfo = data.data;

            var statusDisplay = "";
            switch(userInfo.status) {
                case "正常":
                    statusDisplay = "✅ 正常";
                    break;
                case "会员":
                    statusDisplay = "👑会员";
                    break;
                case "封禁":
                    statusDisplay = "🚫 封禁";
                    break;
                default:
                    statusDisplay = userInfo.status;
            }

            var email = userInfo.email || "未绑定";
            var maskedEmail = "未绑定";
            if (email !== "未绑定" && email.includes("@")) {
                var parts = email.split("@");
                var username = parts[0];
                var domain = parts[1];
                if (username.length > 2) {
                    maskedEmail = username.substring(0, 2) + "****@" + domain;
                } else {
                    maskedEmail = username + "****@" + domain;
                }
            }

            var nickname = userInfo.nickname || "未设置";
            if (nickname === "未设置") {
                nickname = "👤 " + nickname;
            } else {
                nickname = "👤 " + nickname;
            }

            var displayContent = 
                "\n────────────\n" +
                "📊 用 户 信 息 📊\n" +
                "────────────\n" +
                nickname + "\n" +
                "────────────\n" +
                "📧 绑定邮箱\n" + maskedEmail + "\n" +
                "────────────\n" +
                "📊 累计阅读\n" + userInfo.total_usage + " 次\n" +
                "────────────\n" +
                "📈 今日阅读\n" + userInfo.today_usage + " 次\n" +
                "────────────\n" +
                "🔄 账户状态\n" + statusDisplay + "\n" +
                "────────────\n" +
                "📅 注册时间\n" + userInfo.created_at + "\n";

            if (userInfo.is_banned) {
                displayContent += "────────────\n" +
                                "🚫 封禁信息\n" + userInfo.banned_info + "\n";
            }

            if (userInfo.last_used !== "从未使用") {
                displayContent += "────────────\n" +
                                "⏰ 最后使用\n" + userInfo.last_used + "\n";
            }

            if (userInfo.is_member) {
                displayContent += "────────────\n" +
                                "👑会员状态\n 尊贵VIP会员\n";
            }

            displayContent += "────────────\n" +
                            "✨ 查询完成";

            java.longToast(displayContent);

        } else {
            var errorMsg = data.message || "未知错误";

            java.longToast(
                "❌ 查询失败：" + errorMsg
            );
        }

    } catch (e) {
        java.longToast(
            "❌ 网络连接异常，请稍后重试"
        );
    }
}

